class KeyStore:
    """Manages signing and verification keys for different algorithms and sources."""

    def __init__(self):
        self._symmetric_keys: Dict[str, bytes] = {}
        self._private_keys: Dict[str, Any] = {}
        self._public_keys: Dict[str, Any] = {}
        self._key_algorithms: Dict[str, Algorithm] = {}

    def register_symmetric_key(self, key_id: str, secret: Union[str, bytes], algorithm: Algorithm = Algorithm.HS256):
        if algorithm not in (Algorithm.HS256, Algorithm.HS384, Algorithm.HS512):
            raise ValueError(f"Algorithm {algorithm.value} is not a symmetric algorithm")
        if isinstance(secret, str):
            secret = secret.encode("utf-8")
        min_lengths = {Algorithm.HS256: 32, Algorithm.HS384: 48, Algorithm.HS512: 64}
        if len(secret) < min_lengths.get(algorithm, 32):
            raise ValueError(
                f"Secret key for {algorithm.value} should be at least {min_lengths[algorithm]} bytes for security"
            )
        self._symmetric_keys[key_id] = secret
        self._key_algorithms[key_id] = algorithm

    def register_rsa_private_key(self, key_id: str, private_key_pem: Union[str, bytes],
                                  algorithm: Algorithm = Algorithm.RS256, password: Optional[bytes] = None):
        if algorithm not in (Algorithm.RS256, Algorithm.RS384, Algorithm.RS512,
                             Algorithm.PS256, Algorithm.PS384, Algorithm.PS512):
            raise ValueError(f"Algorithm {algorithm.value} is not an RSA algorithm")
        if isinstance(private_key_pem, str):
            private_key_pem = private_key_pem.encode("utf-8")
        private_key = serialization.load_pem_private_key(
            private_key_pem, password=password, backend=default_backend()
        )
        self._private_keys[key_id] = private_key
        self._public_keys[key_id] = private_key.public_key()
        self._key_algorithms[key_id] = algorithm

    def register_rsa_public_key(self, key_id: str, public_key_pem: Union[str, bytes],
                                 algorithm: Algorithm = Algorithm.RS256):
        if algorithm not in (Algorithm.RS256, Algorithm.RS384, Algorithm.RS512,
                             Algorithm.PS256, Algorithm.PS384, Algorithm.PS512):
            raise ValueError(f"Algorithm {algorithm.value} is not an RSA algorithm")
        if isinstance(public_key_pem, str):
            public_key_pem = public_key_pem.encode("utf-8")
        public_key = serialization.load_pem_public_key(
            public_key_pem, backend=default_backend()
        )
        self._public_keys[key_id] = public_key
        self._key_algorithms[key_id] = algorithm

    def register_ec_private_key(self, key_id: str, private_key_pem: Union[str, bytes],
                                 algorithm: Algorithm = Algorithm.ES256, password: Optional[bytes] = None):
        if algorithm not in (Algorithm.ES256, Algorithm.ES384, Algorithm.ES512):
            raise ValueError(f"Algorithm {algorithm.value} is not an EC algorithm")
        if isinstance(private_key_pem, str):
            private_key_pem = private_key_pem.encode("utf-8")
        private_key = serialization.load_pem_private_key(
            private_key_pem, password=password, backend=default_backend()
        )
        self._private_keys[key_id] = private_key
        self._public_keys[key_id] = private_key.public_key()
        self._key_algorithms[key_id] = algorithm

    def register_ec_public_key(self, key_id: str, public_key_pem: Union[str, bytes],
                                algorithm: Algorithm = Algorithm.ES256):
        if algorithm not in (Algorithm.ES256, Algorithm.ES384, Algorithm.ES512):
            raise ValueError(f"Algorithm {algorithm.value} is not an EC algorithm")
        if isinstance(public_key_pem, str):
            public_key_pem = public_key_pem.encode("utf-8")
        public_key = serialization.load_pem_public_key(
            public_key_pem, backend=default_backend()
        )
        self._public_keys[key_id] = public_key
        self._key_algorithms[key_id] = algorithm

    def get_signing_key(self, key_id: str) -> Any:
        if key_id in self._symmetric_keys:
            return self._symmetric_keys[key_id]
        if key_id in self._private_keys:
            return self._private_keys[key_id]
        raise KeyError(f"No signing key found for key_id: {key_id}")

    def get_verification_key(self, key_id: str) -> Any:
        if key_id in self._symmetric_keys:
            return self._symmetric_keys[key_id]
        if key_id in self._public_keys:
            return self._public_keys[key_id]
        raise KeyError(f"No verification key found for key_id: {key_id}")

    def get_algorithm(self, key_id: str) -> Algorithm:
        if key_id not in self._key_algorithms:
            raise KeyError(f"No algorithm registered for key_id: {key_id}")
        return self._key_algorithms[key_id]

    def list_key_ids(self) -> List[str]:
        all_ids = set(self._symmetric_keys.keys()) | set(self._private_keys.keys()) | set(self._public_keys.keys())
        return list(all_ids)


class JWTWrapper:
    """JWT library wrapper supporting multiple signing algorithms."""

