        algorithm = self._key_store.get_algorithm(key_id)
        signing_key = self._key_store.get_signing_key(key_id)

        now = datetime.datetime.now(tz=datetime.timezone.utc)
        token_payload = dict(payload)

        # Set standard claims if not already present
        if "iat" not in token_payload:
            token_payload["iat"] = now
        if "exp" not in token_payload and config.expiration_minutes > 0:
            token_payload["exp"] = now + datetime.timedelta(minutes=config.expiration_minutes)
        if config.issuer and "iss" not in token_payload:
            token_payload["iss"] = config.issuer
        if config.audience and "aud" not in token_payload:
            token_payload["aud"] = config.audience

        headers = {"kid": key_id}
        if additional_headers:
            headers.update(additional_headers)

        token = jwt.encode(
            token_payload,
            signing_key,
            algorithm=algorithm.value,
            headers=headers,
        )
        return token

